// subscriber/subscriber.go
package subscriber

import (
    "context"
    "encore.dev/pubsub"
    "encore.dev/storage/sqldb"
)

type MessageEvent struct {
    Message string
}

var Subscription = pubsub.NewSubscription("message-sub", "message-topic", pubsub.SubscriptionConfig{
    Handler: handleMessage,
})

func handleMessage(ctx context.Context, event *MessageEvent) error {
    _, err := sqldb.Exec(ctx, "INSERT INTO messages (message) VALUES ($1)", event.Message)
    return err
}

type MessagesResponse struct {
    Messages []MessageEntry `json:"messages"`
}

type MessageEntry struct {
    Message string `json:"message"`
}

//encore:api public
func GetMessages(ctx context.Context) (*MessagesResponse, error) {
    rows, err := sqldb.Query(ctx, "SELECT message FROM messages")
    if err != nil {
        return nil, err
    }
    defer rows.Close()

    var messages []MessageEntry
    for rows.Next() {
        var msg string
        if err := rows.Scan(&msg); err != nil {
            return nil, err
        }
        messages = append(messages, MessageEntry{Message: msg})
    }
    if messages == nil {
        messages = []MessageEntry{}
    }
    return &MessagesResponse{Messages: messages}, nil
}
```

